/// Use this when you only need standard CRUD operations.
///
/// # Example
///
/// ```ignore
/// let module = ManufacturingModule::builder().with_database(pool).build()?;
/// let routes = create_stateless_routes(&module);
/// let app = Router::new().merge(routes);
/// ```
pub fn create_stateless_routes(module: &crate::ManufacturingModule) -> Router<()> {
    Router::new()
        .merge(create_workstation_routes(module.workstation_service.clone()))
        .merge(create_operation_routes(module.operation_service.clone()))
        .merge(create_bom_routes(module.bom_service.clone()))
        .merge(create_bom_item_routes(module.bom_item_service.clone()))
        .merge(create_bom_operation_routes(module.bom_operation_service.clone()))
        .merge(create_work_order_routes(module.work_order_service.clone()))
        .merge(create_work_order_item_routes(module.work_order_item_service.clone()))
        .merge(create_job_card_routes(module.job_card_service.clone()))
}

